QUIZ_DATA['01 — Bits, Bytes & Number Systems'] = {"questions": [{"question": "What physically stores a single bit in DRAM?", "options": ["A transistor", "A capacitor", "A magnetic platter", "A floating gate"], "correctAnswer": "A capacitor", "explanation": "DRAM stores each bit as charge in a tiny capacitor. The capacitor leaks charge over time, which is why DRAM needs periodic refreshing (~64ms per row)."}, {"question": "How many unique values can 8 bits represent?", "options": ["128", "255", "256", "512"], "correctAnswer": "256", "explanation": "8 bits = 2^8 = 256 unique values. Range depends on interpretation: 0-255 (unsigned) or -128 to 127 (two's complement signed)."}, {"question": "What is the decimal value of binary 1011?", "correctAnswer": "11", "acceptableAnswers": ["eleven", "11"], "explanation": "1011 binary = 1*8 + 0*4 + 1*2 + 1*1 = 8 + 0 + 2 + 1 = 11."}, {"question": "What does the hexadecimal digit F represent in decimal?", "options": ["10", "14", "15", "16"], "correctAnswer": "15", "explanation": "Hexadecimal uses 0-9 and A-F. A=10, B=11, C=12, D=13, E=14, F=15."}, {"question": "How many bytes are in a kilobyte (binary, not decimal)?", "options": ["1000", "1024", "512", "2048"], "correctAnswer": "1024", "explanation": "In computing, a kilobyte (KiB) is 2^10 = 1024 bytes. The decimal kilobyte (1000 bytes) is used for storage marketing but not for memory addressing."}, {"question": "What is the largest unsigned integer representable in 4 bits?", "correctAnswer": "15", "acceptableAnswers": ["fifteen", "15"], "explanation": "4 bits can represent 2^4 = 16 values (0-15). The largest is 15 (binary 1111)."}, {"question": "Which numbering system uses digits 0-7?", "options": ["Binary", "Octal", "Decimal", "Hexadecimal"], "correctAnswer": "Octal", "explanation": "Octal uses base-8 with digits 0-7. It was historically popular because 3 bits = 1 octal digit (e.g., Unix file permissions use octal notation)."}]};

QUIZ_DATA['02 — Negative Numbers & Endianness'] = {"questions": [{"question": "In two's complement, how do you negate a number?", "options": ["Flip all bits", "Flip all bits and add 1", "Set the MSB to 1", "Subtract from 255"], "correctAnswer": "Flip all bits and add 1", "explanation": "Two's complement negation: invert all bits (one's complement), then add 1. Example: 5 (00000101) \u2192 flip (11111010) \u2192 add 1 (11111011) = -5."}, {"question": "What is the two's complement representation of -1 in 8 bits?", "correctAnswer": "11111111", "acceptableAnswers": ["0xFF", "FF", "255", "11111111"], "explanation": "-1 in two's complement is all bits set to 1. For 8 bits: 11111111. This works because 11111111 + 1 = 00000000 (overflow discarded), giving 0."}, {"question": "What is the range of an 8-bit signed integer?", "options": ["0 to 255", "-128 to 127", "-127 to 128", "-256 to 255"], "correctAnswer": "-128 to 127", "explanation": "8-bit signed: -2^7 to 2^7-1 = -128 to 127. The asymmetry (-128 exists but +128 doesn't) is a two's complement property: 10000000 = -128."}, {"question": "In big-endian byte order, where is the most significant byte stored?", "options": ["At the lowest memory address", "At the highest memory address", "In the CPU register", "It depends on the operating system"], "correctAnswer": "At the lowest memory address", "explanation": "Big-endian stores the most significant byte at the lowest address (the 'big end' first). Network byte order is big-endian. Little-endian (x86) stores the least significant byte first."}, {"question": "What problem does sign extension solve?", "options": ["Adding two negative numbers", "Converting a smaller signed integer to a larger one", "Detecting overflow", "Converting between endian formats"], "correctAnswer": "Converting a smaller signed integer to a larger one", "explanation": "Sign extension copies the sign bit to all new higher bits when widening a signed integer. Example: int8_t -5 (11111011) \u2192 int16_t (11111111 11111011) = still -5."}]};

QUIZ_DATA['03 — Assembly Language'] = {"questions": [{"question": "What does the x86 instruction `mov eax, [ebx]` do?", "options": ["Copy EAX value into EBX", "Load value at memory address in EBX into EAX", "Move the address of EBX into EAX", "Compare EAX and EBX"], "correctAnswer": "Load value at memory address in EBX into EAX", "explanation": "Brackets `[]` denote memory dereference. `mov eax, [ebx]` loads the 32-bit value at the memory address stored in EBX into register EAX."}, {"question": "How many general-purpose registers does x86-64 have (excluding stack/base pointer)?", "correctAnswer": "14", "acceptableAnswers": ["14", "fourteen"], "explanation": "x86-64 has 16 GPRs: RAX, RBX, RCX, RDX, RSI, RDI, RBP, RSP, and R8-R15. Excluding RSP (stack pointer) and RBP (base pointer), 14 remain for general use."}, {"question": "What is the difference between `cmp` and `sub` on x86?", "options": ["cmp modifies the destination, sub doesn't", "sub modifies the destination, cmp doesn't", "They are identical", "cmp works only on registers"], "correctAnswer": "sub modifies the destination, cmp doesn't", "explanation": "`cmp a, b` computes a-b and sets flags but discards the result. `sub a, b` computes a-b, sets flags, AND stores the result in a. cmp is used before conditional jumps."}, {"question": "Which flag is set when an arithmetic operation results in zero?", "correctAnswer": "ZF", "acceptableAnswers": ["ZF", "Zero Flag", "zero flag"], "explanation": "The Zero Flag (ZF) is set to 1 when an operation produces a zero result. `je` (jump if equal) checks ZF=1. cmp followed by je is how if/else compiles."}, {"question": "What does `jne` (jump if not equal) check?", "options": ["ZF=0", "CF=1", "SF=1", "OF=0"], "correctAnswer": "ZF=0", "explanation": "jne checks if ZF (Zero Flag) is 0, meaning the previous comparison was NOT equal. jne and jnz are the same instruction with different mnemonics."}, {"question": "What is a 'nop sled' used for in assembly?", "options": ["Performance optimization", "Padding code to align jump targets", "Exploit development", "All of the above"], "correctAnswer": "All of the above", "explanation": "NOP (0x90) instructions are multi-purpose: aligning jump targets to cache line boundaries (perf), filling unused space, and in exploit development as a 'landing zone' for shellcode."}]};

QUIZ_DATA['04 — CPU Architecture'] = {"questions": [{"question": "What are the four stages of the classic CPU instruction cycle?", "correctAnswer": "Fetch, Decode, Execute, Writeback", "acceptableAnswers": ["fetch decode execute writeback", "fetch, decode, execute, writeback", "Fetch Decode Execute Writeback"], "explanation": "Fetch: load instruction from memory (PC \u2192 instruction register). Decode: determine what the instruction does. Execute: ALU performs the operation. Writeback: store result to register."}, {"question": "What is the purpose of a branch predictor?", "options": ["To speed up memory access", "To guess which way a conditional branch will go", "To decode instructions faster", "To manage power consumption"], "correctAnswer": "To guess which way a conditional branch will go", "explanation": "The branch predictor guesses whether a conditional jump will be taken BEFORE the condition is evaluated. This keeps the pipeline full. A misprediction costs 15-20 cycles as the pipeline is flushed."}, {"question": "What does 'superscalar' mean in CPU architecture?", "options": ["The CPU runs at a higher clock speed", "The CPU can execute multiple instructions per clock cycle", "The CPU has multiple cores", "The CPU uses a larger cache"], "correctAnswer": "The CPU can execute multiple instructions per clock cycle", "explanation": "Superscalar CPUs have multiple execution units that can process independent instructions simultaneously. Modern CPUs issue 4-8 instructions per cycle (4-wide to 8-wide)."}, {"question": "What happens during a pipeline stall?", "options": ["The CPU powers down", "The CPU switches to a different thread", "A later pipeline stage waits for an earlier instruction to complete", "The clock speed is reduced"], "correctAnswer": "A later pipeline stage waits for an earlier instruction to complete", "explanation": "A pipeline stall occurs when an instruction depends on the result of a previous instruction that hasn't completed yet. The dependent instruction must wait, creating a 'bubble' in the pipeline."}, {"question": "What is the typical penalty for a branch misprediction on modern CPUs?", "correctAnswer": "15-20", "acceptableAnswers": ["15-20 cycles", "15-20", "15 to 20 cycles"], "explanation": "When the branch predictor guesses wrong, the speculatively executed instructions must be discarded and the pipeline restarted from the correct path. This costs ~15-20 cycles on modern x86."}]};

QUIZ_DATA['05 — Memory Hierarchy'] = {"questions": [{"question": "What is the typical size of an L1 data cache on a modern CPU core?", "options": ["8KB", "32-64KB", "256-512KB", "2-4MB"], "correctAnswer": "32-64KB", "explanation": "L1 data cache is typically 32KB (Zen 4) or 48KB (Raptor Lake). It's the smallest and fastest cache, with ~4-5 cycle latency."}, {"question": "How many bytes are in an x86 cache line?", "correctAnswer": "64", "acceptableAnswers": ["64", "64 bytes"], "explanation": "x86 CPUs use 64-byte cache lines. When any byte in a cache line is accessed, the entire 64-byte line is loaded from the next cache level. This is why sequential access is fast (spatial locality)."}, {"question": "Why does false sharing hurt performance?", "options": ["It increases memory usage", "Threads on different cores invalidate each other's cache lines", "It causes the CPU to use incorrect data", "It disables the cache entirely"], "correctAnswer": "Threads on different cores invalidate each other's cache lines", "explanation": "False sharing: two threads modify different variables that happen to share a cache line. Each write invalidates the other core's cache line, causing constant cache misses despite no actual data sharing."}, {"question": "What is the approximate latency difference between L1 cache and main memory access?", "options": ["2x", "10x", "100x", "1000x"], "correctAnswer": "100x", "explanation": "L1 cache: ~1ns (4 cycles at 4GHz). DDR5 DRAM: ~80-100ns. That's roughly 100x difference. In CPU cycles: L1 = 4 cycles, DRAM = ~200-400 cycles."}, {"question": "What does the MESI protocol ensure?", "correctAnswer": "Cache coherence", "acceptableAnswers": ["cache coherence", "Cache Coherence", "Cache coherence across cores"], "explanation": "MESI (Modified, Exclusive, Shared, Invalid) is a cache coherence protocol that ensures all CPU cores see a consistent view of memory. It tracks the state of each cache line across all caches."}]};

QUIZ_DATA['06 — Memory Allocation'] = {"questions": [{"question": "What does `malloc(size)` return when allocation fails?", "options": ["0", "An invalid pointer", "NULL", "It throws an exception"], "correctAnswer": "NULL", "explanation": "malloc returns NULL on failure. Always check the return value. In C++, `new` throws std::bad_alloc (unless `nothrow` is used). UE's `FMemory::Malloc` returns nullptr on failure."}, {"question": "What problem does the buddy allocator solve?", "options": ["Memory leaks", "External fragmentation", "Slow allocation speed", "Cache misses"], "correctAnswer": "External fragmentation", "explanation": "The buddy allocator divides memory into power-of-two blocks. When a block is freed, it's merged with its 'buddy' (adjacent equal-sized block), reducing external fragmentation. Used in Linux kernel page allocation."}, {"question": "What is internal fragmentation?", "correctAnswer": "Wasted space inside an allocated block", "acceptableAnswers": ["wasted space inside allocated blocks", "Wasted space inside an allocated block", "unused space within an allocation"], "explanation": "Internal fragmentation: allocated block is larger than requested. Example: requesting 10 bytes, allocator gives 16 bytes (minimum block size). The 6 extra bytes are internal fragmentation."}, {"question": "What does `sbrk()` do on Linux?", "options": ["Allocates a specific amount of memory", "Moves the program break to expand/shrink the heap", "Frees allocated memory", "Locks a memory region"], "correctAnswer": "Moves the program break to expand/shrink the heap", "explanation": "sbrk(increment) adjusts the program's data segment break. Positive increment \u2192 expand heap. Negative \u2192 shrink. Modern allocators prefer mmap over sbrk for large allocations."}, {"question": "Why is `mmap` preferred over `sbrk` for large allocations?", "options": ["mmap is faster", "mmap allows returning memory to the OS immediately", "mmap uses less memory", "mmap doesn't require system calls"], "correctAnswer": "mmap allows returning memory to the OS immediately", "explanation": "sbrk can only grow/shrink at the break boundary. If allocated blocks exist beyond the freed region, sbrk can't shrink. mmap maps independent pages that can be munmap'd immediately regardless of order."}]};

QUIZ_DATA['07 — Virtual Memory — The Full Picture'] = {"questions": [{"question": "What is the size of a standard page on x86-64?", "correctAnswer": "4KB", "acceptableAnswers": ["4KB", "4096 bytes", "4 KB", "4096"], "explanation": "The standard page size on x86-64 is 4KB (4096 bytes). Huge pages: 2MB (PSE) and 1GB (PDPE). The page size balances TLB coverage vs internal fragmentation."}, {"question": "How many levels are in the x86-64 page table hierarchy?", "options": ["2", "3", "4", "5"], "correctAnswer": "4", "explanation": "x86-64 uses 4-level paging: PML4 \u2192 PDPT \u2192 PD \u2192 PT (9 bits per level). Each level has 512 entries. The virtual address is split: [16 unused | 9 PML4 | 9 PDPT | 9 PD | 9 PT | 12 offset]."}, {"question": "What happens during a TLB miss?", "options": ["The program crashes", "The CPU performs a page walk to find the translation", "The OS swaps the page to disk", "The CPU retries the instruction"], "correctAnswer": "The CPU performs a page walk to find the translation", "explanation": "On TLB miss, the MMU walks the page table hierarchy (up to 4 memory accesses for 4-level paging) to find the PTE. The translation is then cached in the TLB for future use."}, {"question": "What does the 'dirty' bit in a PTE indicate?", "options": ["The page has been read", "The page has been written to", "The page is corrupted", "The page is in swap"], "correctAnswer": "The page has been written to", "explanation": "The dirty bit indicates the page has been modified since it was loaded. When evicting a page, if dirty=1, the page must be written back to disk. If dirty=0, the page can simply be discarded."}, {"question": "What is the purpose of KPTI (Kernel Page Table Isolation)?", "correctAnswer": "Mitigate the Meltdown vulnerability", "acceptableAnswers": ["Mitigate Meltdown", "Meltdown mitigation", "Protect against Meltdown"], "explanation": "KPTI unmaps kernel pages from userspace page tables to prevent Meltdown attacks. The kernel has its own separate page table. Every syscall must switch page tables, adding 100-500+ cycles overhead."}, {"question": "What does `mmap` with MAP_ANONYMOUS do?", "options": ["Maps a file into memory", "Allocates anonymous memory not backed by a file", "Shares memory between processes", "Locks memory in RAM"], "correctAnswer": "Allocates anonymous memory not backed by a file", "explanation": "MAP_ANONYMOUS creates a mapping not backed by any file. It's how malloc typically allocates large blocks: mmap(NULL, size, PROT_READ|PROT_WRITE, MAP_PRIVATE|MAP_ANONYMOUS, -1, 0)."}]};

QUIZ_DATA['08 — RAID'] = {"questions": [{"question": "What does RAID 0 provide?", "options": ["Redundancy", "Striping for performance", "Mirroring", "Error correction"], "correctAnswer": "Striping for performance", "explanation": "RAID 0 (striping) splits data across multiple disks for parallel read/write, improving throughput. No redundancy \u2014 a single disk failure loses all data. Capacity = N \u00d7 disk_size."}, {"question": "What is the minimum number of disks required for RAID 5?", "correctAnswer": "3", "acceptableAnswers": ["three", "3", "3 disks"], "explanation": "RAID 5 requires at least 3 disks: data distributed across N-1 disks plus one disk's worth of parity. It can survive one disk failure. Capacity = (N-1) \u00d7 disk_size."}, {"question": "What is the 'write hole' problem in RAID 5?", "options": ["A physical defect in the disk platter", "Data and parity becoming inconsistent after a crash during a write", "A security vulnerability", "A performance bottleneck"], "correctAnswer": "Data and parity becoming inconsistent after a crash during a write", "explanation": "RAID 5 write requires updating data AND parity on separate disks. If a crash occurs between these two writes, data and parity are inconsistent. ZFS and some hardware RAID controllers use copy-on-write to avoid this."}, {"question": "Which RAID level provides mirroring?", "correctAnswer": "RAID 1", "acceptableAnswers": ["RAID 1", "1", "raid 1"], "explanation": "RAID 1 mirrors all data across two or more disks. Every write goes to all mirrors. Capacity = disk_size (for 2-disk mirror). Can survive N-1 disk failures. Simplest redundancy."}]};

QUIZ_DATA['09 — DMA & Bus Mastering'] = {"questions": [{"question": "What is the primary benefit of DMA over programmed I/O?", "options": ["Higher security", "Frees the CPU during data transfers", "Lower latency", "Better error handling"], "correctAnswer": "Frees the CPU during data transfers", "explanation": "DMA allows peripherals to transfer data directly to/from memory without CPU involvement per byte. CPU sets up the transfer and goes back to useful work. The DMA controller handles the actual data movement."}, {"question": "What does the DMA controller need from the CPU before starting a transfer?", "options": ["The data to transfer", "Source address, destination address, and transfer size", "A list of free memory pages", "The CPU's permission every cycle"], "correctAnswer": "Source address, destination address, and transfer size", "explanation": "CPU programs the DMA controller with: source address, destination address, transfer count, and direction (read/write). After setup, the DMA controller operates independently."}, {"question": "What is bus mastering?", "correctAnswer": "A device taking control of the memory bus to perform transfers independently", "acceptableAnswers": ["A device controlling the bus for DMA", "When a device takes control of the bus", "device controls the bus for direct memory access"], "explanation": "Bus mastering: a peripheral device becomes the bus master, driving address and control lines to read/write memory directly. The CPU is temporarily disconnected from the bus during the transfer."}, {"question": "What happens when DMA and CPU try to access memory simultaneously?", "options": ["The system crashes", "The DMA controller always wins", "Cycle stealing \u2014 DMA uses cycles the CPU doesn't need", "They share the bus equally"], "correctAnswer": "Cycle stealing \u2014 DMA uses cycles the CPU doesn't need", "explanation": "DMA uses 'cycle stealing': it transfers one word at a time during cycles when the CPU doesn't need the memory bus. The CPU is only stalled if both need memory simultaneously."}, {"question": "What does an IOMMU do?", "options": ["Encrypts DMA transfers", "Translates device virtual addresses to physical addresses", "Speeds up DMA transfers", "Compresses data during transfer"], "correctAnswer": "Translates device virtual addresses to physical addresses", "explanation": "IOMMU (I/O Memory Management Unit) provides address translation for DMA, similar to the MMU for CPU. Enables: device isolation (VM passthrough), scatter-gather, and protection against malicious DMA."}]};

QUIZ_DATA['10 — Networking — TCP, UDP & Sockets'] = {"questions": [{"question": "What is the key difference between TCP and UDP?", "options": ["TCP is faster", "TCP is connection-oriented with guaranteed delivery", "UDP supports larger packets", "TCP uses less memory"], "correctAnswer": "TCP is connection-oriented with guaranteed delivery", "explanation": "TCP: connection-oriented, guaranteed in-order delivery, flow control, congestion control. UDP: connectionless, no delivery guarantees, no ordering. TCP for reliability (web, file transfer), UDP for speed (games, VoIP)."}, {"question": "What is the three-way handshake in TCP?", "correctAnswer": "SYN, SYN-ACK, ACK", "acceptableAnswers": ["SYN SYN-ACK ACK", "syn synack ack"], "explanation": "TCP connection setup: Client sends SYN with random sequence number. Server responds with SYN-ACK (acknowledging client's SYN, sending its own SYN). Client sends ACK. Connection established. Adds 1 RTT latency."}, {"question": "What port range is available for user applications?", "options": ["0-1023", "1024-49151", "49152-65535", "All ports are available"], "correctAnswer": "1024-49151", "explanation": "Ports 0-1023: well-known (HTTP:80, SSH:22). 1024-49151: registered ports (can be used by applications). 49152-65535: dynamic/private ports (ephemeral, used for client connections)."}, {"question": "What does the TCP Nagle algorithm do?", "options": ["Prioritizes ACK packets", "Delays small packets to combine them", "Encrypts the TCP stream", "Increases the window size"], "correctAnswer": "Delays small packets to combine them", "explanation": "Nagle's algorithm delays sending small segments until previous data is acknowledged OR enough data accumulates to fill a segment. Reduces overhead for many small writes. Can be disabled with TCP_NODELAY for low-latency apps (games)."}, {"question": "What socket call prepares a server to accept connections?", "options": ["socket()", "connect()", "listen()", "bind()"], "correctAnswer": "listen()", "explanation": "Sequence: socket() \u2192 bind() \u2192 listen() \u2192 accept(). listen() marks the socket as passive and creates the backlog queue for incoming connections. accept() blocks until a client connects."}]};

QUIZ_DATA['11 — Boot Process — BIOS, UEFI & Bootloader'] = {"questions": [{"question": "What is the first code the CPU executes after power-on?", "options": ["The OS kernel", "The bootloader", "Firmware (BIOS/UEFI)", "The CPU's built-in self-test"], "correctAnswer": "Firmware (BIOS/UEFI)", "explanation": "After power-on, the CPU fetches its first instruction from the reset vector (physical address 0xFFFFFFF0 on x86). This points to the firmware (BIOS/UEFI), which performs POST and hardware initialization."}, {"question": "What does POST stand for?", "correctAnswer": "Power-On Self-Test", "acceptableAnswers": ["Power On Self Test", "Power-On Self Test"], "explanation": "POST is the firmware's initial hardware check: CPU registers, memory (counting RAM), basic I/O devices. Failures are signaled via beep codes or LED patterns before any display output is available."}, {"question": "What is the main difference between BIOS and UEFI?", "options": ["BIOS is faster", "UEFI supports larger disks and has a graphical interface", "BIOS is more secure", "UEFI runs on ARM only"], "correctAnswer": "UEFI supports larger disks and has a graphical interface", "explanation": "BIOS: 16-bit real mode, MBR (max 2TB disks), text-only. UEFI: 32/64-bit, GPT (max 9.4 ZB), graphical interface, Secure Boot, network boot built-in. UEFI replaced BIOS as the standard around 2012."}, {"question": "What does the bootloader do after firmware hands off control?", "options": ["Initialize the GPU", "Load the OS kernel into memory", "Run user applications", "Mount the filesystem permanently"], "correctAnswer": "Load the OS kernel into memory", "explanation": "The bootloader (GRUB, Windows Boot Manager) loads the kernel image from disk into memory, sets up initial CPU state (protected/long mode), and jumps to the kernel's entry point. The kernel then takes over."}]};

QUIZ_DATA['12 — GPU Architecture'] = {"questions": [{"question": "How many threads are in an NVIDIA warp?", "correctAnswer": "32", "acceptableAnswers": ["32", "thirty two"], "explanation": "NVIDIA GPUs execute threads in groups of 32 called warps. All threads in a warp execute the same instruction (SIMT \u2014 Single Instruction Multiple Thread). AMD's equivalent is a wavefront of 64 threads."}, {"question": "What happens when threads in a warp take different branch paths?", "options": ["The GPU crashes", "Branch divergence \u2014 both paths execute serially", "Only one path executes", "Threads vote on which path to take"], "correctAnswer": "Branch divergence \u2014 both paths execute serially", "explanation": "Branch divergence: when threads in a warp take different branches, the GPU serializes execution. First all threads taking path A execute (others masked), then path B executes. Performance penalty proportional to divergence."}, {"question": "What is shared memory on a GPU?", "options": ["Memory shared between GPU and CPU", "On-chip SRAM shared between threads in a block", "VRAM accessible by all SMs", "Memory shared between different GPUs"], "correctAnswer": "On-chip SRAM shared between threads in a block", "explanation": "Shared memory is fast on-chip SRAM (~128KB per SM on RTX 4090) shared between all threads in a thread block. ~20-30x lower latency than VRAM. Critical for tiling, reductions, and cooperative algorithms."}, {"question": "Why does a GPU have thousands of cores while a CPU has ~16?", "options": ["GPUs are simpler to manufacture", "GPUs are designed for throughput over latency", "CPU cores are underutilized", "It's just marketing \u2014 GPU cores are the same as CPU cores"], "correctAnswer": "GPUs are designed for throughput over latency", "explanation": "CPUs optimize for single-thread latency (branch prediction, OoO execution, large caches). GPUs optimize for throughput: hide memory latency by switching between thousands of threads. A GPU 'core' is simpler than a CPU core."}]};

QUIZ_DATA['13 — Interrupts & Exceptions'] = {"questions": [{"question": "What is the difference between an interrupt and an exception?", "options": ["Interrupts are synchronous, exceptions are asynchronous", "Interrupts come from external hardware, exceptions come from the CPU", "They are the same thing", "Interrupts are handled by the OS, exceptions by the CPU"], "correctAnswer": "Interrupts come from external hardware, exceptions come from the CPU", "explanation": "Interrupts: asynchronous, from external hardware (keyboard, NIC, timer). Exceptions: synchronous, from CPU (division by zero, page fault, illegal instruction). Both use the interrupt descriptor table (IDT) for handling."}, {"question": "What is the purpose of the Interrupt Descriptor Table (IDT)?", "options": ["To list all connected devices", "To map interrupt vectors to handler functions", "To track interrupt priorities", "To store interrupt statistics"], "correctAnswer": "To map interrupt vectors to handler functions", "explanation": "The IDT is a CPU data structure (256 entries on x86) that maps each interrupt/exception vector to its handler (ISR). The CPU indexes into the IDT when an interrupt occurs to find the correct handler address."}, {"question": "Why should interrupt service routines (ISRs) be as short as possible?", "options": ["To save memory", "Interrupts are disabled during ISR execution", "The CPU runs slower in ISR mode", "ISRs have limited stack space"], "correctAnswer": "Interrupts are disabled during ISR execution", "explanation": "During an ISR, interrupts of equal or lower priority are masked. Long ISRs delay other interrupts, causing missed deadlines (audio pops, network packet loss). Split work into: top-half (ISR, minimal) and bottom-half (deferred work)."}, {"question": "What does the APIC do?", "options": ["Encrypts interrupt signals", "Routes interrupts to specific CPU cores", "Amplifies interrupt signals", "Logs interrupt events"], "correctAnswer": "Routes interrupts to specific CPU cores", "explanation": "The Advanced Programmable Interrupt Controller routes interrupts to specific cores, handles interrupt priority, and enables inter-processor interrupts (IPIs). The LAPIC (local) is per-core; the IO-APIC handles external devices."}, {"question": "What is an interrupt storm?", "correctAnswer": "A device generating interrupts faster than the CPU can handle them", "acceptableAnswers": ["too many interrupts", "device flooding CPU with interrupts", "excessive interrupt rate"], "explanation": "An interrupt storm: a device generates interrupts at a rate exceeding the CPU's ability to service them. The CPU spends 100% time in ISRs, starving user processes. Fixed by interrupt coalescing or rate limiting in the driver."}]};
